import{_ as e,c as a,o,aj as t}from"./chunks/framework.CLcCQpUA.js";const i="/ComicGUISpider/assets/conf_usage_en.BUI2jE4i.png",f=JSON.parse('{"title":"🔨 配置","description":"","frontmatter":{},"headers":[],"relativePath":"locate/en/config/index.md","filePath":"locate/en/config/index.md"}'),r={name:"locate/en/config/index.md"},c=t('<h1 id="🔨-配置" tabindex="-1">🔨 配置 <a class="header-anchor" href="#🔨-配置" aria-label="Permalink to &quot;🔨 配置&quot;">​</a></h1><p><img src="'+i+'" alt="conf"></p><div class="info custom-block"><p class="custom-block-title">config file is <code>scripts/conf.yml</code>, generated after initial use</p></div><div class="warning custom-block"><p class="custom-block-title">The input box of multiple lines is in <code>yaml</code> format (except for eh_cookies), and a ⚠️ <code>space</code> ⚠️ is required after the <code>colon</code></p></div><h2 id="config-field-corresponding-yml-field" tabindex="-1">Config Field / Corresponding <code>yml</code> Field <a class="header-anchor" href="#config-field-corresponding-yml-field" aria-label="Permalink to &quot;Config Field / Corresponding `yml` Field&quot;">​</a></h2><h3 id="storage-path-sv-path" tabindex="-1">Storage Path / <code>sv_path</code> <a class="header-anchor" href="#storage-path-sv-path" aria-label="Permalink to &quot;Storage Path / `sv_path`&quot;">​</a></h3><p>Download directory<br> The <code>web</code> folder in the directory structure is because the default association with the <a href="https://github.com/jasoneri/comic_viewer" target="_blank" rel="noreferrer"><code>comic_viewer</code></a> project is set like this</p><h3 id="log-level-log-level" tabindex="-1">Log Level / <code>log_level</code> <a class="header-anchor" href="#log-level-log-level" aria-label="Permalink to &quot;Log Level / `log_level`&quot;">​</a></h3><p>After the background runs, there will be a log directory, which is the same level as the GUI, and the GUI will give operation guidance when an error occurs</p><h3 id="deduplicate-isdeduplicate" tabindex="-1">Deduplicate / <code>isDeduplicate</code> <a class="header-anchor" href="#deduplicate-isdeduplicate" aria-label="Permalink to &quot;Deduplicate / `isDeduplicate`&quot;">​</a></h3><p>When checked, there will be a style hint in the preview window for downloaded<br> At the same time, the download will automatically filter out the existing records</p><div class="info custom-block github-alert"><p class="custom-block-title">Currently only applicable in 🔞</p><p></p></div><h3 id="add-identifier-adduuid" tabindex="-1">Add Identifier / <code>addUuid</code> <a class="header-anchor" href="#add-identifier-adduuid" aria-label="Permalink to &quot;Add Identifier / `addUuid`&quot;">​</a></h3><p>Add an identifier at the end of the directory when storing, which is used to handle different works with the same name</p><h3 id="proxy-proxies" tabindex="-1">Proxy / <code>proxies</code> <a class="header-anchor" href="#proxy-proxies" aria-label="Permalink to &quot;Proxy / `proxies`&quot;">​</a></h3><p>Use for wall-breaking</p><div class="info custom-block github-alert"><p class="custom-block-title">It is recommended to configure the proxy here, rather than the global proxy mode, otherwise a lot of proxy traffic will be consumed when accessing the source</p><p></p></div><h3 id="mapping-custom-map" tabindex="-1">Mapping / <code>custom_map</code> <a class="header-anchor" href="#mapping-custom-map" aria-label="Permalink to &quot;Mapping / `custom_map`&quot;">​</a></h3><p>Search input mapping<br> When the search does not meet the preset, first add the key-value pair here, and after restarting, the corresponding website results will be output when entering the custom key in the search box</p><ol><li>Mapping does not need to care about the domain name, as long as it is used in the current website, as long as it meets <code>can access without mapping</code> and <code>the entered is not an invalid url</code>, the program will automatically replace it with a usable domain name, such as <code>wnacg.com</code> will be automatically replaced with the default domain name under non-proxy mapping</li><li>Note that the custom mapping may exceed the range of the paging rule, and at this time, it can be notified to the developer for expansion</li></ol><h3 id="preset-completer" tabindex="-1">Preset / <code>completer</code> <a class="header-anchor" href="#preset-completer" aria-label="Permalink to &quot;Preset / `completer`&quot;">​</a></h3><p>Custom preset<br> There will be a <code>number corresponding to the website</code> prompt when the mouse hovers over the input box (in fact, it is the number of the choose-box)</p><h3 id="eh-cookies-eh-cookies" tabindex="-1">Eh Cookies / <code>eh_cookies</code> <a class="header-anchor" href="#eh-cookies-eh-cookies" aria-label="Permalink to &quot;Eh Cookies / `eh_cookies`&quot;">​</a></h3><p>It is necessary to use <code>exhentai</code><br><a href="https://raw.githubusercontent.com/jasoneri/imgur/main/CGS/ehentai_get_cookies_new.gif" target="_blank" rel="noreferrer">🎬 Method of acquisition</a><br><a href="https://tool.lu/en_US/curl/" target="_blank" rel="noreferrer">🔗 Tool Website</a></p><h3 id="clipboard-db-clip-db" tabindex="-1">Clipboard Db / <code>clip_db</code> <a class="header-anchor" href="#clipboard-db-clip-db" aria-label="Permalink to &quot;Clipboard Db / `clip_db`&quot;">​</a></h3><p>When the clipboard reading function cannot be used, check whether the path exists, and change it here after obtaining the correct path</p><ol><li>ditto(win): Open options → Database path</li><li>maccy(macOS): <a href="https://github.com/p0deje/Maccy/issues/271" target="_blank" rel="noreferrer">issue search for related information</a></li></ol><h3 id="read-number-clip-read-num" tabindex="-1">Read Number / <code>clip_read_num</code> <a class="header-anchor" href="#read-number-clip-read-num" aria-label="Permalink to &quot;Read Number / `clip_read_num`&quot;">​</a></h3><p>Number of items read from the clipboard software</p>',29),d=[c];function l(n,s,h,p,u,m){return o(),a("div",null,d)}const g=e(r,[["render",l]]);export{f as __pageData,g as default};
